import React from 'react';


function QuestionCard(params){

  const question = params.params;
  const question_id = question.id;
   
    return(
        <div id="questionCard">
         
        <div class="card">
            <h5 class="card-header">{question.titel}</h5>
            <div class="card-body">
              <h5 class="card-title">{question.subtitle}</h5>
              <p class="card-text">{question.description}</p>
              
              <div class="form-check">
                <input class="form-check-input" type="radio" name="inlineRadioOptions" id={{question_id}&&"inlineRadio1"} value="1"></input>
                <label class="form-check-label" for="inlineRadio1">{question.answers[0].a1}</label>
                </div>
              <div class="form-check">
                <input class="form-check-input" type="radio" name="inlineRadioOptions" id={{question_id}&&"inlineRadio2"} value="2"></input>
                <label class="form-check-label" for="inlineRadio2">{question.answers[0].a2} </label>
              </div>
              <div class="form-check">
                <input class="form-check-input" type="radio" name="inlineRadioOptions" id={{question_id}&&"inlineRadio3"} value="3"></input>
                <label class="form-check-label" for="inlineRadio3">{question.answers[0].a3}</label>
              </div>
              <div class="form-check">
                <input class="form-check-input" type="radio" name="inlineRadioOptions" id={{question_id}&&"inlineRadio4"} value="4"></input>
                <label class="form-check-label" for="inlineRadio4">{question.answers[0].a4}</label>
              </div>
              </div> 
            </div>
            </div>
        
      
        )
    
 
}


export default QuestionCard;
